[最小K个数](https://leetcode-cn.com/problems/zui-xiao-de-kge-shu-lcof)
```C++
class Solution {
public:
    vector<int> getLeastNumbers(vector<int>& arr, int k) {
        quick_sorr(arr,0,arr.size()-1);
        vector<int> temp;
        temp.assign(arr.begin(),arr.begin()+k);
        return temp;
    }
private:
void quick_sorr(vector<int>& arr,int l,int r){
    if(l>=r) return;
    int i=l-1,j=r+1,x=arr[(l + r) >> 1];
    while(i<j){
        do i++;while(arr[i]<x);
        do j--;while(x<arr[j]);
        if(i<j) swap(arr[i],arr[j]);
    }
    quick_sorr(arr,l,j),quick_sorr(arr,j+1,r);
}
};
